export interface SmsDelivery {
  id: string;
  phoneNumber: string;
  message: string;
  sentAt: Date;
}

export class SmsNotificationHandler implements NotificationChannelHandler {
  private logger = new Logger('SmsNotificationHandler');
  private deliveredMessages: SmsDelivery[] = [];

  constructor(private eventBus: EventBus) {
    this.eventBus.on<NotificationSendEvent>('notification:send', (event) => {
      this.handle(event);
    });
  }

  handle(event: NotificationSendEvent): void {
    const delivery: SmsDelivery = {
      id: generateNotificationId(),
      phoneNumber: event.recipient,
      message: `${event.subject}: ${event.body}`,
      sentAt: new Date(),
    };
    this.deliveredMessages.push(delivery);
    this.logger.info(`SMS sent: ${delivery.id} to ${event.recipient}`);
  }

  getDeliveredMessages(): SmsDelivery[] {
    return [...this.deliveredMessages];
  }

  clearDeliveredMessages(): void {
    this.deliveredMessages = [];
  }
}

export interface WebhookDelivery {
