        recipient: event.recipient,
        subject: event.subject,
        body: event.body,
        timestamp: event.timestamp,
      },
      deliveredAt: new Date(),
    };
    this.deliveredWebhooks.push(delivery);
    this.logger.info(`Webhook delivered: ${delivery.id} for ${event.recipient}`);
  }

  getDeliveredWebhooks(): WebhookDelivery[] {
    return [...this.deliveredWebhooks];
  }

  clearDeliveredWebhooks(): void {
    this.deliveredWebhooks = [];
  }
}

